    97→/**
    98→ * Lockfile to package manager mapping (priority order: bun > yarn > pnpm > npm)
    99→ */
   100→const LOCKFILE_PRIORITY: Array<{ file: string; pm: PackageManager }> = [
   101→  { file: "bun.lockb", pm: "bun" },
   102→  { file: "bun.lock", pm: "bun" },
   103→  { file: "yarn.lock", pm: "yarn" },
   104→  { file: "pnpm-lock.yaml", pm: "pnpm" },
   105→  { file: "package-lock.json", pm: "npm" },
   106→];
   107→
   108→/**
   109→ * Detect package manager from lockfiles
   110→ * Priority: bun > yarn > pnpm > npm
   111→ * Falls back to npm if no lockfile found but package.json exists
   112→ */
   113→export async function detectPackageManager(): Promise<PackageManager | null> {
   114→  // Check lockfiles in priority order
   115→  for (const { file, pm } of LOCKFILE_PRIORITY) {
   116→    if (await fileExists(file)) {
   117→      return pm;
   118→    }
   119→  }
   120→
   121→  // Fallback to npm if package.json exists
   122→  if (await fileExists("package.json")) {
   123→    return "npm";
   124→  }
   125→
   126→  // Not a Node.js project
   127→  return null;
   128→}
