   330→export async function detectStack(): Promise<string | null> {
   331→  // Check for Next.js config files
   332→  for (const file of STACKS.nextjs.detection.files || []) {
   333→    if (await fileExists(file)) {
   334→      return "nextjs";
   335→    }
   336→  }
   337→
   338→  // Check for Astro config files
   339→  for (const file of STACKS.astro.detection.files || []) {
   340→    if (await fileExists(file)) {
   341→      return "astro";
   342→    }
   343→  }
   344→
   345→  // Check for SvelteKit config files
   346→  for (const file of STACKS.sveltekit.detection.files || []) {
   347→    if (await fileExists(file)) {
   348→      return "sveltekit";
   349→    }
   350→  }
   351→
   352→  // Check for Remix config files
   353→  for (const file of STACKS.remix.detection.files || []) {
   354→    if (await fileExists(file)) {
   355→      return "remix";
   356→    }
   357→  }
   358→
   359→  // Check for Nuxt config files
   360→  for (const file of STACKS.nuxt.detection.files || []) {
   361→    if (await fileExists(file)) {
   362→      return "nuxt";
   363→    }
   364→  }
   365→
   366→  // Check package.json for all JS framework dependencies (read once)
   367→  // Priority order: Next.js > Astro > SvelteKit > Remix > Nuxt
   368→  if (await fileExists("package.json")) {
   369→    try {
   370→      const pkg = JSON.parse(await readFile("package.json"));
   371→      const deps = { ...pkg.dependencies, ...pkg.devDependencies };
   372→      if (deps.next) return "nextjs";
   373→      if (deps.astro) return "astro";
   374→      if (deps["@sveltejs/kit"]) return "sveltekit";
   375→      if (deps["@remix-run/react"]) return "remix";
   376→      if (deps.nuxt) return "nuxt";
   377→    } catch {
   378→      // Ignore parse errors
   379→    }
   380→  }
   381→
   382→  // Check for Rust
   383→  if (await fileExists("Cargo.toml")) {
   384→    return "rust";
   385→  }
   386→
   387→  // Check for Go
   388→  if (await fileExists("go.mod")) {
   389→    return "go";
   390→  }
   391→
   392→  // Check for Python
   393→  for (const file of STACKS.python.detection.files || []) {
   394→    if (await fileExists(file)) {
   395→      return "python";
   396→    }
   397→  }
   398→
   399→  return null;
   400→}
