   402→/**
   403→ * Detect stack in a specific directory
   404→ * Similar to detectStack but operates on a given path
   405→ *
   406→ * @param basePath - Directory path to check (relative to cwd)
   407→ * @returns Stack name or null if not detected
   408→ */
   409→export async function detectStackInDirectory(
   410→  basePath: string,
   411→): Promise<string | null> {
   412→  const pathPrefix = basePath ? `${basePath}/` : "";
   413→
   414→  // Check for Next.js config files
   415→  for (const file of STACKS.nextjs.detection.files || []) {
   416→    if (await fileExists(`${pathPrefix}${file}`)) {
   417→      return "nextjs";
   418→    }
   419→  }
   420→
   421→  // Check for Astro config files
   422→  for (const file of STACKS.astro.detection.files || []) {
   423→    if (await fileExists(`${pathPrefix}${file}`)) {
   424→      return "astro";
   425→    }
   426→  }
   427→
   428→  // Check for SvelteKit config files
   429→  for (const file of STACKS.sveltekit.detection.files || []) {
   430→    if (await fileExists(`${pathPrefix}${file}`)) {
   431→      return "sveltekit";
   432→    }
   433→  }
   434→
   435→  // Check for Remix config files
   436→  for (const file of STACKS.remix.detection.files || []) {
   437→    if (await fileExists(`${pathPrefix}${file}`)) {
   438→      return "remix";
   439→    }
   440→  }
   441→
   442→  // Check for Nuxt config files
   443→  for (const file of STACKS.nuxt.detection.files || []) {
   444→    if (await fileExists(`${pathPrefix}${file}`)) {
   445→      return "nuxt";
   446→    }
   447→  }
   448→
   449→  // Check package.json for JS framework dependencies
   450→  const packageJsonPath = `${pathPrefix}package.json`;
   451→  if (await fileExists(packageJsonPath)) {
   452→    try {
   453→      const pkg = JSON.parse(await readFile(packageJsonPath));
   454→      const deps = { ...pkg.dependencies, ...pkg.devDependencies };
   455→      if (deps.next) return "nextjs";
   456→      if (deps.astro) return "astro";
   457→      if (deps["@sveltejs/kit"]) return "sveltekit";
   458→      if (deps["@remix-run/react"]) return "remix";
   459→      if (deps.nuxt) return "nuxt";
   460→    } catch {
   461→      // Ignore parse errors
   462→    }
   463→  }
   464→
   465→  // Check for Rust
   466→  if (await fileExists(`${pathPrefix}Cargo.toml`)) {
   467→    return "rust";
   468→  }
   469→
   470→  // Check for Go
   471→  if (await fileExists(`${pathPrefix}go.mod`)) {
   472→    return "go";
   473→  }
   474→
   475→  // Check for Python
   476→  for (const file of STACKS.python.detection.files || []) {
   477→    if (await fileExists(`${pathPrefix}${file}`)) {
   478→      return "python";
   479→    }
   480→  }
   481→
   482→  return null;
   483→}
