   485→/**
   486→ * Detect all stacks in the repository
   487→ *
   488→ * Traverses root and immediate subdirectories (1 level deep) to find
   489→ * all stacks present in a monorepo or multi-stack project.
   490→ *
   491→ * @returns Array of detected stacks with their paths
   492→ */
   493→export async function detectAllStacks(): Promise<DetectedStack[]> {
   494→  const results: DetectedStack[] = [];
   495→
   496→  // Check root directory
   497→  const rootStack = await detectStackInDirectory("");
   498→  if (rootStack) {
   499→    results.push({ stack: rootStack, path: "" });
   500→  }
   501→
   502→  // Check immediate subdirectories (1 level deep)
   503→  try {
   504→    const entries = await readdir(".", { withFileTypes: true });
   505→
   506→    for (const entry of entries) {
   507→      if (!entry.isDirectory()) continue;
   508→      if (SKIP_DIRECTORIES.includes(entry.name)) continue;
   509→      if (entry.name.startsWith(".")) continue; // Skip hidden directories
   510→
   511→      const subdirStack = await detectStackInDirectory(entry.name);
   512→      if (subdirStack) {
   513→        // Skip if same stack as root (likely a false positive)
   514→        // e.g., both root and /packages/web detect "nextjs"
   515→        // We want distinct stacks, not duplicates
   516→        const isDuplicate = results.some(
   517→          (r) => r.stack === subdirStack && r.path === "",
   518→        );
   519→
   520→        // Only skip if root has the same stack AND this is a common mono-repo pattern
   521→        // (like packages/, apps/, etc.)
   522→        if (
   523→          !isDuplicate ||
   524→          entry.name === "frontend" ||
   525→          entry.name === "backend"
   526→        ) {
   527→          results.push({ stack: subdirStack, path: entry.name });
   528→        }
   529→      }
   530→    }
   531→  } catch {
   532→    // Directory read failed, return what we have
   533→  }
   534→
   535→  return results;
   536→}
