    24→// Get the package templates directory
    25→function getTemplatesDir(): string {
    26→  const __dirname = dirname(fileURLToPath(import.meta.url));
    27→  // Compiled structure: dist/src/lib/templates.js
    28→  // So we need ../../../templates to reach project root templates/
    29→  const devPath = join(__dirname, "..", "..", "..", "templates");
    30→
    31→  return devPath;
    32→}
