    34→/**
    35→ * Process template variables in content
    36→ */
    37→export function processTemplate(
    38→  content: string,
    39→  variables: Record<string, string>,
    40→): string {
    41→  let result = content;
    42→  for (const [key, value] of Object.entries(variables)) {
    43→    result = result.replace(new RegExp(`\\{\\{${key}\\}\\}`, "g"), value);
