    51→export async function listTemplateFiles(): Promise<string[]> {
    52→  const templatesDir = getTemplatesDir();
    53→  const files: string[] = [];
    54→
    55→  async function walk(dir: string, prefix: string = ""): Promise<void> {
    56→    try {
    57→      const entries = await readdir(dir, { withFileTypes: true });
    58→      for (const entry of entries) {
    59→        const relativePath = join(prefix, entry.name);
    60→        const fullPath = join(dir, entry.name);
    61→
    62→        if (entry.isDirectory()) {
    63→          await walk(fullPath, relativePath);
    64→        } else {
    65→          files.push(join("templates", relativePath));
    66→        }
    67→      }
    68→    } catch {
    69→      // Directory doesn't exist
    70→    }
    71→  }
    72→
    73→  await walk(templatesDir);
    74→  return files;
    75→}
    76→
    77→/**
    78→ * Get content of a template file
    79→ */
    80→export async function getTemplateContent(
    81→  templatePath: string,
    82→): Promise<string> {
    83→  const templatesDir = getTemplatesDir();
    84→  const relativePath = templatePath.replace("templates/", "");
    85→  const fullPath = join(templatesDir, relativePath);
    86→
    87→  return readFile(fullPath);
    88→}
    89→
    90→/**
    91→ * Result of symlink creation attempt
    92→ */
    93→export interface SymlinkResult {
    94→  created: boolean;
    95→  path: string;
    96→  target: string;
    97→  fallbackToCopy: boolean;
    98→  skipped: boolean;
    99→  reason?: string;
   100→}
   101→
   102→/**
   103→ * Options for copyTemplates
   104→ */
   105→export interface CopyTemplatesOptions {
   106→  /** Use copies instead of symlinks for scripts (Windows default or user preference) */
   107→  noSymlinks?: boolean;
   108→  /** Force replacement of existing files/symlinks */
   109→  force?: boolean;
   110→  /** Additional stacks to include in constitution notes (for multi-stack projects) */
   111→  additionalStacks?: string[];
   112→}
   113→
   114→/**
   115→ * Create symlinks for files in a directory, with fallback to copy
   116→ * @param srcDir Source directory containing template files
   117→ * @param destDir Destination directory for symlinks
   118→ * @param options Options controlling symlink behavior
   119→ * @returns Array of results for each file
   120→ */
   121→export async function symlinkDir(
   122→  srcDir: string,
   123→  destDir: string,
   124→  options: { force?: boolean } = {},
   125→): Promise<SymlinkResult[]> {
   126→  const results: SymlinkResult[] = [];
   127→
   128→  try {
   129→    const entries = await readdir(srcDir, { withFileTypes: true });
   130→    await ensureDir(destDir);
   131→
   132→    for (const entry of entries) {
   133→      if (entry.isDirectory()) {
   134→        // Recursively handle subdirectories
   135→        const subResults = await symlinkDir(
   136→          join(srcDir, entry.name),
   137→          join(destDir, entry.name),
   138→          options,
   139→        );
   140→        results.push(...subResults);
   141→        continue;
   142→      }
   143→
   144→      const srcPath = join(srcDir, entry.name);
   145→      const destPath = join(destDir, entry.name);
   146→
   147→      // Calculate relative path from destDir to srcPath for portable symlinks
   148→      // Note: srcPath may already be absolute (when srcDir is absolute), so check first
   149→      const absoluteDest = isAbsolute(destPath)
   150→        ? destPath
   151→        : join(process.cwd(), destPath);
   152→      const absoluteSrc = isAbsolute(srcPath)
   153→        ? srcPath
   154→        : join(process.cwd(), srcPath);
   155→      const relativeTarget = relative(dirname(absoluteDest), absoluteSrc);
   156→
   157→      // Check if destination already exists
   158→      // Note: isSymlink uses lstat and works on broken symlinks,
   159→      // while fileExists uses access which fails on broken symlinks
   160→      const destIsSymlink = await isSymlink(destPath);
   161→      const destExists = destIsSymlink || (await fileExists(destPath));
   162→
   163→      if (destExists && !destIsSymlink && !options.force) {
   164→        // Regular file exists and force not specified - skip
   165→        results.push({
   166→          created: false,
   167→          path: destPath,
   168→          target: relativeTarget,
   169→          fallbackToCopy: false,
   170→          skipped: true,
   171→          reason: "existing file (use --force to replace)",
   172→        });
   173→        continue;
   174→      }
   175→
   176→      // Remove existing file/symlink if force or if it's already a symlink
   177→      // (symlinks are always replaced to ensure they point to correct target)
   178→      if (destExists && (options.force || destIsSymlink)) {
   179→        await removeFileOrSymlink(destPath);
   180→      }
   181→
   182→      // Try to create symlink
   183→      const symlinkCreated = await createSymlink(relativeTarget, destPath);
   184→
   185→      if (symlinkCreated) {
   186→        results.push({
   187→          created: true,
   188→          path: destPath,
   189→          target: relativeTarget,
   190→          fallbackToCopy: false,
   191→          skipped: false,
   192→        });
   193→      } else {
   194→        // Symlink failed (likely Windows without privileges) - fall back to copy
   195→        const content = await readFile(srcPath);
   196→        await writeFile(destPath, content);
   197→
   198→        // Make shell scripts executable
   199→        if (entry.name.endsWith(".sh")) {
   200→          await chmod(destPath, 0o755);
   201→        }
   202→
   203→        results.push({
   204→          created: true,
   205→          path: destPath,
   206→          target: relativeTarget,
   207→          fallbackToCopy: true,
   208→          skipped: false,
   209→          reason: "symlink not supported, copied instead",
   210→        });
   211→      }
   212→    }
   213→  } catch (error) {
   214→    // Skip if source doesn't exist
   215→    if ((error as NodeJS.ErrnoException).code !== "ENOENT") {
   216→      throw error;
   217→    }
   218→  }
   219→
   220→  return results;
   221→}
   222→
   223→/**
   224→ * Copy all templates to .claude/ directory
   225→ */
   226→export async function copyTemplates(
   227→  stack: string,
   228→  tokens?: Record<string, string>,
   229→  options: CopyTemplatesOptions = {},
   230→): Promise<{ scriptsSymlinked: boolean; symlinkResults?: SymlinkResult[] }> {
   231→  const templatesDir = getTemplatesDir();
   232→  const stackConfig = getStackConfig(stack);
   233→
   234→  // Detect project name from available sources (package.json, Cargo.toml, etc.)
   235→  const projectName = await getProjectName();
   236→
   237→  // Get stack-specific notes for constitution template
   238→  // Use multi-stack notes if additional stacks are provided
   239→  const stackNotes =
   240→    options.additionalStacks && options.additionalStacks.length > 0
   241→      ? getMultiStackNotes(stack, options.additionalStacks)
   242→      : getStackNotes(stack);
   243→
   244→  const variables = {
   245→    ...stackConfig.variables,
   246→    ...tokens,
   247→    PROJECT_NAME: projectName,
   248→    STACK: stack,
   249→    STACK_NOTES: stackNotes,
   250→  };
   251→
   252→  async function copyDir(srcDir: string, destDir: string): Promise<void> {
   253→    try {
   254→      const entries = await readdir(srcDir, { withFileTypes: true });
   255→      await ensureDir(destDir);
   256→
   257→      for (const entry of entries) {
   258→        const srcPath = join(srcDir, entry.name);
   259→        const destPath = join(destDir, entry.name);
   260→
   261→        if (entry.isDirectory()) {
   262→          await copyDir(srcPath, destPath);
   263→        } else {
   264→          // Read, process, and write
   265→          let content = await readFile(srcPath);
   266→          content = processTemplate(content, variables);
   267→          await writeFile(destPath, content);
   268→
   269→          // Make shell scripts executable
   270→          if (entry.name.endsWith(".sh")) {
   271→            await chmod(destPath, 0o755);
   272→          }
   273→        }
   274→      }
   275→    } catch (error) {
   276→      // Skip if source doesn't exist
   277→      if ((error as NodeJS.ErrnoException).code !== "ENOENT") {
   278→        throw error;
   279→      }
   280→    }
   281→  }
   282→
   283→  // Copy skills
   284→  await copyDir(join(templatesDir, "skills"), ".claude/skills");
   285→
   286→  // Copy hooks
   287→  await copyDir(join(templatesDir, "hooks"), ".claude/hooks");
   288→
   289→  // Copy memory (constitution, etc.)
   290→  await copyDir(join(templatesDir, "memory"), ".claude/memory");
   291→
   292→  // Handle scripts directory - use symlinks unless disabled
   293→  const useSymlinks = !options.noSymlinks && !isNativeWindows();
   294→  let scriptsSymlinked = false;
   295→  let symlinkResults: SymlinkResult[] | undefined;
   296→
   297→  if (useSymlinks) {
   298→    // Use symlinks for scripts - they don't need template variable processing
   299→    symlinkResults = await symlinkDir(
   300→      join(templatesDir, "scripts"),
   301→      "scripts/dev",
   302→      { force: options.force },
   303→    );
   304→
   305→    // Check if any symlinks were actually created (not all fell back to copy)
   306→    scriptsSymlinked = symlinkResults.some(
   307→      (r) => r.created && !r.fallbackToCopy,
   308→    );
   309→  } else {
   310→    // Fall back to copies (Windows or --no-symlinks flag)
   311→    await copyDir(join(templatesDir, "scripts"), "scripts/dev");
   312→  }
   313→
   314→  // Copy settings.json
   315→  const settingsPath = join(templatesDir, "settings.json");
   316→  if (await fileExists(settingsPath)) {
   317→    const content = await readFile(settingsPath);
   318→    await writeFile(
   319→      ".claude/settings.json",
   320→      processTemplate(content, variables),
   321→    );
   322→  }
   323→
   324→  // Write skills version marker for sync detection
   325→  await writeFile(SKILLS_VERSION_PATH, getPackageVersion());
   326→
   327→  return { scriptsSymlinked, symlinkResults };
   328→}
