  const stackConfig: StackConfigFile = {
    primary: { name: stack! },
    additional: additionalStacks.map((name) => ({ name })),
  };
  await saveStackConfig(stackConfig);
  console.log(chalk.blue("📋 Saved multi-stack configuration"));
}

