        return path === "package.json";
      });
      mockReadFile.mockResolvedValue(
        JSON.stringify({
          devDependencies: { nuxt: "^3.0.0" },
        }),
      );

      const result = await detectStack();
      expect(result).toBe("nuxt");
    });
